class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def is_prime(n):
            if n < 2:
                return False
            for i in range(2, int(n**0.5) + 1):
                if n % i == 0:
                    return False
            return True

        res = []
        prime_count = [0] * (10**5 + 1)
        for num in nums:
            if is_prime(num):
                prime_count[num] += 1

        for query in queries:
            idx, val = query
            if is_prime(nums[idx]):
                prime_count[nums[idx]] -= 1
            if is_prime(val):
                prime_count[val] += 1
            nums[idx] = val

            max_count = 0
            for k in range(1, len(nums)):
                left_count = sum(prime_count[num] for num in nums[:k] if prime_count[num] > 0)
                right_count = sum(prime_count[num] for num in nums[k:] if prime_count[num] > 0)
                max_count = max(max_count, left_count + right_count)
            res.append(max_count)
        return res
